import type { Player } from '../types';
import { ResultBuilder, type GameActionResult, type QuestStateChange } from './ResultBuilder';

export type QuestType = 'main' | 'side' | 'daily' | 'weekly' | 'chain' | 'hidden' | 'legendary';
export type QuestStatus = 'locked' | 'available' | 'in_progress' | 'completed' | 'failed' | 'abandoned';
export type ObjectiveType = 'kill' | 'collect' | 'explore' | 'talk' | 'deliver' | 'craft' | 'reach_level' | 'use_skill' | 'survive' | 'time_attack';

export interface Quest {
    id: string;
    name: string;
    description: string;
    type: QuestType;
    status: QuestStatus;
    level: number;
    objectives: QuestObjective[];
    rewards: QuestReward;
    prerequisites?: string[];
    nextQuest?: string;
    chainId?: string;
    chainPosition?: number;
    timeLimit?: number;
    repeatable?: boolean;
    cooldown?: number;
    icon: string;
    giver?: string;
    location?: string;
    lore?: string;
}

export interface QuestObjective {
    id: string;
    type: ObjectiveType;
    description: string;
    target: string;
    current: number;
    required: number;
    optional: boolean;
    hidden: boolean;
}

export interface QuestReward {
    exp?: number;
    gold?: number;
    items?: QuestItemReward[];
    cards?: string[];
    reputation?: { faction: string; value: number }[];
    unlocks?: string[];
    achievement?: string;
}

export interface QuestItemReward {
    id: string;
    name: string;
    quantity: number;
    chance: number;
}

export interface QuestChain {
    id: string;
    name: string;
    description: string;
    quests: string[];
    completionReward: QuestReward;
    icon: string;
}

export interface RandomEvent {
    id: string;
    name: string;
    description: string;
    type: EventType;
    probability: number;
    conditions?: EventCondition[];
    choices: EventChoice[];
    icon: string;
    location?: string;
}

export type EventType = 'encounter' | 'treasure' | 'merchant' | 'shrine' | 'trap' | 'mystery' | 'story';

export interface EventCondition {
    type: 'level' | 'quest' | 'item' | 'stat' | 'location' | 'time';
    key: string;
    operator: '==' | '!=' | '>' | '<' | '>=' | '<=' | 'has';
    value: unknown;
}

export interface EventChoice {
    id: string;
    text: string;
    icon: string;
    outcome: EventOutcome;
    condition?: EventCondition;
}

export interface EventOutcome {
    success: boolean;
    message: string;
    effects: EventEffect[];
}

export interface EventEffect {
    type: 'gain_gold' | 'lose_gold' | 'gain_item' | 'lose_item' | 'gain_exp' | 'gain_stat' | 'lose_stat' | 'start_combat' | 'teleport' | 'unlock_quest' | 'trigger_event';
    value: number | string;
    target?: string;
}

export interface Achievement {
    id: string;
    name: string;
    description: string;
    category: AchievementCategory;
    icon: string;
    requirement: AchievementRequirement;
    reward: QuestReward;
    progress: number;
    target: number;
    unlocked: boolean;
    unlockedAt?: number;
    hidden: boolean;
}

export type AchievementCategory = 'combat' | 'exploration' | 'collection' | 'social' | 'crafting' | 'story' | 'challenge' | 'hidden';

export interface AchievementRequirement {
    type: 'kill_count' | 'quest_complete' | 'item_collect' | 'level_reach' | 'gold_earn' | 'card_collect' | 'boss_defeat' | 'time_played' | 'combo_count' | 'damage_dealt';
    target: string | number;
    count: number;
}

